Code.Terraform:
```hcl
# Terraform: フルパケットのデフォルトステートレスアクションをドロップに設定します
resource "aws_networkfirewall_firewall_policy" "<example_resource_name>" {
  name = "<example_resource_name>"

  firewall_policy {
    stateless_default_actions          = ["aws:drop"]  # 重要: フルパケットのデフォルトはドロップに設定されています（チェックを修正）
    stateless_fragment_default_actions = ["aws:drop"]  # 有効なポリシーに必要です
  }
}
```
